import React from "react";
import clsx from "clsx";
const colorMap = { blue:"bg-blue-50 text-blue-600", green:"bg-emerald-50 text-emerald-600", purple:"bg-purple-50 text-purple-600", orange:"bg-orange-50 text-orange-600", red:"bg-red-50 text-red-600", indigo:"bg-indigo-50 text-indigo-600" };
export default function StatsCard({ title, value, subtitle, icon: Icon, color = "blue", trend }) {
  return (
    <div className="stat-card animate-in">
      <div>
        <p className="text-sm text-slate-500 font-medium">{title}</p>
        <p className="text-3xl font-bold text-slate-900 mt-1">{value ?? "—"}</p>
        {subtitle && <p className="text-xs text-slate-400 mt-1">{subtitle}</p>}
        {trend !== undefined && <span className={clsx("text-xs font-medium mt-1 inline-block", trend >= 0 ? "text-emerald-600" : "text-red-500")}>{trend >= 0 ? "↑" : "↓"} {Math.abs(trend)}% vs last month</span>}
      </div>
      {Icon && <div className={clsx("w-11 h-11 rounded-xl flex items-center justify-center flex-shrink-0", colorMap[color])}><Icon className="w-6 h-6" /></div>}
    </div>
  );
}
